55	    fn new(socket: TcpStream, src_addr: SocketAddr, dst_addr: SocketAddr) -> LinkUnicastTcp {
56	        // Set the TCP nodelay option
57	        if let Err(err) = socket.set_nodelay(true) {
58	            tracing::warn!(
59	                "Unable to set NODEALY option on TCP link {} => {}: {}",
60	                src_addr,
61	                dst_addr,
62	                err
63	            );
64	        }
65	
66	        // Set the TCP linger option
67	        #[allow(deprecated)]
68	        if let Err(err) = socket.set_linger(Some(Duration::from_secs(
69	            (*TCP_LINGER_TIMEOUT).try_into().unwrap(),
70	        ))) {
71	            tracing::warn!(
72	                "Unable to set LINGER option on TCP link {} => {}: {}",
73	                src_addr,
74	                dst_addr,
75	                err
76	            );
77	        }
78	
79	        // Compute the MTU
80	        // See IETF RFC6691: https://datatracker.ietf.org/doc/rfc6691/
81	        let header = match src_addr.ip() {
82	            std::net::IpAddr::V4(_) => 40,
