    match &self.variant {
        LinkUnicastUdpVariant::Reliable(_) => true,
        LinkUnicastUdpVariant::Connected(_) | LinkUnicastUdpVariant::Unconnected(_) => {
            super::IS_RELIABLE
        }
    }
}

